from flask import Flask, request, redirect, session, render_template, url_for
from flask_mail import Mail, Message
import random
import os
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)
app.secret_key = os.urandom(24)
mail = Mail(app)

# Mock user data for demonstration
users = {
    "testuser": generate_password_hash("password123")
}

# Mail configuration
app.config['MAIL_SERVER'] = 'smtp.example.com'
app.config['MAIL_PORT'] = 587
app.config['MAIL_USE_TLS'] = True
app.config['MAIL_USERNAME'] = 'your-email@example.com'
app.config['MAIL_PASSWORD'] = 'your-password'
mail.init_app(app)

# Generate MFA token
def generate_mfa_token():
    return str(random.randint(100000, 999999))

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form['username']
        password = request.form['password']
        if username in users and check_password_hash(users[username], password):
            session['username'] = username
            mfa_token = generate_mfa_token()
            session['mfa_token'] = mfa_token
            msg = Message('Your MFA Token', sender='your-email@example.com', recipients=[username])
            msg.body = f'Your MFA token is: {mfa_token}'
            mail.send(msg)
            return redirect(url_for('verify_mfa'))
        return 'Invalid username or password'
    return render_template('login.html')

@app.route('/verify-mfa', methods=['GET', 'POST'])
def verify_mfa():
    if request.method == 'POST':
        entered_token = request.form['mfa_token']
        if entered_token == session['mfa_token']:
            session.pop('mfa_token', None)
            return 'Access Granted to Protected Resource'
        return 'Invalid MFA Token'
    return render_template('verify_mfa.html')

@app.route('/protected')
def protected():
    if 'username' not in session:
        return redirect(url_for('login'))
    return 'This is a protected resource.'

if __name__ == '__main__':
    app.run(debug=True)